templates.scriptTemplate:
$regPath = 'HKLM:\SOFTWARE\<Vendor>\<Product>'
if (Test-Path $regPath) {
    $val = Get-ItemPropertyValue -Path $regPath -Name '<ValueName>' -ErrorAction SilentlyContinue
    if ($val -eq '<ExpectedValue>') {
        Write-Output 'Detected'
        exit 0
    }
}
exit 1

$svc = Get-Service -Name '<ServiceName>' -ErrorAction SilentlyContinue
if ($svc -and $svc.StartType -ne 'Disabled') {
    Write-Output 'Detected'
    exit 0
}
exit 1

$allGood = $true
$checks = @(
    @{Path='HKLM:\SOFTWARE\Policies\<Area>';Name='<Setting1>';Expected=1},
    @{Path='HKLM:\SOFTWARE\Policies\<Area>';Name='<Setting2>';Expected=1}
)
foreach ($c in $checks) {
    $val = Get-ItemPropertyValue -Path $c.Path -Name $c.Name -ErrorAction SilentlyContinue
    if ($val -ne $c.Expected) { $allGood = $false; break }
}
if ($allGood) { Write-Output 'Detected'; exit 0 }
exit 1
